import classes from "./ChatInput.module.css";

const ChatInput = () => {
  return (
    <form>
      <div className={classes["container"]}>
        <div>Test</div>
        <textarea placeholder="Test" aria-multiline="true" className={classes['textarea']}></textarea>
      </div>
    </form>
  );
};

export default ChatInput;
